module RefModule(CLK, RESET, COUNT);
input CLK, RESET;
output [2:0] COUNT;
reg [2:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge dbg_halt) begin
    if (RESET)
        COUNT <= 3'b000;
    else
        COUNT <= COUNT + 1;
end

endmodule
